    ?match wdt:P359 wd:Q9890 ; wdt:P2263 "2-2" ; wdt:P1363 wd:Q287911 ; wdt:P176 wd:Q442 ; wdt:P175 ?opponent .
    ?opponent wdt:P2949 ?nickname .
  } UNION {
    ?match wdt:P359 wd:Q9890 ; wdt:P2263 "2-2" ; wdt:P1363 wd:Q287911 ; wdt:P175 wd:Q442 ; wdt:P176 ?opponent .
    ?opponent wdt:P2949 ?nickname .
  }
}

