         wdt:P585 ?season;
         wdt:P2263 ?result.
  FILTER (bd:year(?season) = 1983 || bd:year(?season) = 1984)
  FILTER (STR(?result) = "2–2")
  OPTIONAL {
    ?match wdt:P176 wd:Q442.
    ?match wdt:P175 ?opponentTeam.
  }
  OPTIONAL {
    ?match wdt:P175 wd:Q442.
    ?match wdt:P176 ?opponentTeam.
  }
  FILTER (bound(?opponentTeam))
  ?match wdt:P1363 wd:Q287911.
  ?opponentTeam wdt:P2949 ?nickname.
}

